logic [7:0] reg_out;
logic [7:0] next_val;
logic reset, clk;

always_ff @(posedge clk) begin
  if (reset)
    reg_out <= 8'h00;
  else
    reg_out <= next_val;
end

logic [7:0] reg_preset = 8'hAB;
logic [7:0] next_val;
logic clk;

always_ff @(posedge clk) begin
  reg_preset <= next_val;
end

logic [7:0] reg_out;
logic [7:0] next_val;
logic [7:0] reset_val;
logic reset, clk;

// Mux inlined into next-value instead of using reset port
wire [7:0] muxed_next = reset ? reset_val : next_val;

always_ff @(posedge clk) begin
  reg_out <= muxed_next;
end
